from flask import Flask, request, jsonify
from flask_login import LoginManager, UserMixin, login_user, current_user, logout_user
from werkzeug.security import generate_password_hash, check_password_hash
import base64
import os
from cryptography.fernet import Fernet

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'  # Replace with your secret key
login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin):
    def __init__(self, id, email, password, two_fa_enabled):
        self.id = id
        self.email = email
        self.password = password
        self.two_fa_enabled = two_fa_enabled

class Database:
    users = {
        1: User(1, 'user@example.com', generate_password_hash('password'), False),
        # Add more user instances if needed
    }

    def get_user(self, email):
        for user in self.users.values():
            if user.email == email:
                return user
        return None

db = Database()
fernet = Fernet(base64.b32decode(os.urandom(32)))

@login_manager.user_loader
def load_user(user_id):
    return db.users[int(user_id)]

@app.route('/api/login', methods=['POST'])
def login():
    email = request.json.get('email')
    password = request.json.get('password')
    user = db.get_user(email)
    if not user or not check_password_hash(user.password, password):
        return jsonify({'error': 'Invalid email or password'}), 401
    token = fernet.encrypt(str(user.id).encode()).decode()
    login_user(user)
    return jsonify({'token': token})

@app.route('/api/logout', methods=['POST'])
def logout():
    logout_user()
    return '', 204

@app.route('/api/profile', methods=['PUT'])
def update_profile():
    user = current_user
    if not user:
        return jsonify({'error': 'Not authenticated'}), 401
    new_email = request.json.get('email')
    new_password = request.json.get('password')
    two_fa_enabled = request.json.get('two_fa_settings', False)
    if new_email and user.email != new_email:
        existing_user = db.get_user(new_email)
        if existing_user:
            return jsonify({'error': 'Email already in use'}), 409
    if new_password:
        user.password = generate_password_hash(new_password)
    user.two_fa_enabled = two_fa_enabled
    db.users[user.id] = user
    return jsonify({})